import { getSupabase } from "../supabase";

export type ProgressSyncPayload = {
  userLevel: number;
  globalXP: number;
  globalXpToNext: number;
  gems: number;
  totalXp: string;
};

let queuedPayload: ProgressSyncPayload | null = null;
let queueBusy = false;

export async function syncProgressStats(payload: ProgressSyncPayload): Promise<boolean> {
  const sb = getSupabase();
  if (!sb) return false;
  const {
    data: { session },
  } = await sb.auth.getSession();
  if (!session?.user) return false;
  const saveData = {
    userLevel: payload.userLevel,
    globalXP: payload.globalXP,
    globalXpToNext: payload.globalXpToNext,
    gems: payload.gems,
    totalXp: payload.totalXp,
  };
  const { error } = await sb
    .from("codesnap_progress_sync")
    .upsert(
      {
        user_id: session.user.id,
        progress: saveData,
        updated_at: new Date().toISOString(),
      },
      { onConflict: "user_id" },
    );
  return !error;
}

export async function submitLeaderboardProgress(input: { score: number; missionType: string }): Promise<boolean> {
  const sb = getSupabase();
  if (!sb) return false;
  const {
    data: { session },
  } = await sb.auth.getSession();
  if (!session?.user) return false;
  const { error } = await sb.from("arena_leaderboards").insert({
    user_id: session.user.id,
    score: Math.max(0, Math.floor(input.score)),
    mission_type: input.missionType.trim() || "PROGRESS",
  });
  return !error;
}

/**
 * Optimistic queue keeps latest payload and flushes sequentially
 * newer updates replace older queued values to avoid stale writes
 */
export async function queueOptimisticProgressSync(payload: ProgressSyncPayload): Promise<void> {
  queuedPayload = payload;
  if (queueBusy) return;
  queueBusy = true;
  try {
    while (queuedPayload) {
      const current = queuedPayload;
      queuedPayload = null;
      await syncProgressStats(current);
    }
  } finally {
    queueBusy = false;
  }
}
